dateFormat : function(date) {
var year = date.getFullYear();
var month = date.getMonth();
if (month < 10) {
month = "0" + month;
}
var day = date.getDay();
if (day < 10) {
day = "0" + day;
}
var hours = date.getHours();
if (hours < 10) {
hours = "0" + hours;
}
var minutes = date.getMinutes();
if (minutes < 10) {
minutes = "0" + minutes;
}
return "" + year + month + day + hours + minutes;
}
}
