kumibanFormat : function(kumiban, kakesikiKbn) {
var fmKumiban = kumiban.substr(0, 1);
for (var i = 1; i < kumiban.length; i++) {
if (kakesikiKbn == "2" || kakesikiKbn == "3" || kakesikiKbn == "6") {
fmKumiban += "-";
} else {
fmKumiban += "=";
}
fmKumiban += kumiban.substr(i, 1);
}
return fmKumiban;
}
}
